#include <bits/stdc++.h> using namespace std; #define ll long long #define ull unsigned long long #define ld long double #define pii pair<int, int> #define pll pair<ll, ll> #define vi vector<int> #define vll vector<ll> #define endl "\n"  void solve(){    int n;    cin >> n;     vi a(n),b(n);    for( int &x : a ) cin >> x;    for( int &x : b ) cin >> x;     int st,end;    for( int i = 0 ;i < n; i++ )    {        if( a[i] != b[i] )        {            st = i;            break;        }    }    end = st;    while( (end < n ) && ( (a[end] != b[end]) || a[end] >= b[end-1] ))    {        end++;    }    while( ( st > 0 ) && ( (a[st-1] == b[st-1]) && (b[st] >= b[st-1] ) )) st--;    cout << st+1 << " " << end <<endl;} int main(){    ios_base ::sync_with_stdio(false);    cin.tie(NULL);     int t=1;    cin >> t;     while (t--)        solve();     return 0;}